INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('9f59a6c47eadc054', 'NY', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in New York for the 2026 cycle?', '["Are Chuck Schumer or Kirsten Gillibrand up for re-election in 2026?","When is the next US Senate election in NY?","New York US Senate seats 2026"]', 'No. There is no regular U.S. Senate election in New York in 2026. Senator Chuck Schumer (Class 3) is not up until 2028, and Senator Kirsten Gillibrand (Class 1) is not up until 2030.', 'https://elections.ny.gov/election-results-and-data', 'New York State Board of Elections – Election Data', '2026-05-11', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('9bac5d9f8933f6df', 'NY', '["state"]', 'candidate_eligibility', 'Are there term limits for the Governor of New York?', '["Can Governor Hochul run for re-election in 2026?","How many terms can a NY Governor serve?","New York gubernatorial term limits"]', 'No. There are no term limits for the Governor of New York or any statewide elected official. Governor Kathy Hochul is eligible to run for re-election in 2026.', 'https://www.nysenate.gov/legislation/laws/CNS/A4', 'New York Constitution Article IV § 1', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('832dde9e296f5d7f', 'NY', '["state"]', 'election_dates', 'Do the Governor and Lieutenant Governor run on the same ticket in the primary election?', '["Are NY Governor and LG elected together?","Joint ticket rules for New York Governor","Do I vote for Governor and LG separately?"]', 'Candidates for Governor and Lieutenant Governor run separately in the partisan primary elections. However, the winners of each primary are paired together and run as a joint ticket on the November General Election ballot.', 'https://www.nysenate.gov/legislation/laws/CNS/A4', 'New York Constitution Article IV § 1', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates and voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('8ffd72d3d64fcbe9', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 New York Primary Election?', '["What date is the NY primary in 2026?","New York 2026 primary date","When do polls open for the NY primary?"]', 'The New York Primary Election is scheduled for Tuesday, June 23, 2026 (the fourth Tuesday in June).', 'https://www.nysenate.gov/legislation/laws/ELN/8-100', 'N.Y. Elec. Law § 8-100(1)(a)', '2026-05-11', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('70d4cd8636b9b4c9', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 New York General Election?', '["What date is the NY general election in 2026?","NY 2026 midterm election date","When is Election Day 2026 in New York?"]', 'The New York General Election is on Tuesday, November 3, 2026.', 'https://www.nysenate.gov/legislation/laws/ELN/8-100', 'N.Y. Elec. Law § 8-100(1)(c)', '2026-05-11', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('382e041ea5a1abf7', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is ''Fusion Voting'' and how does it work in New York?', '["Can a candidate run on multiple party lines in NY?","Cross-endorsement rules New York","How do the Working Families and Conservative parties cross-endorse?"]', 'Under New York''s ''Fusion Voting'' system, multiple political parties can nominate the exact same candidate. The candidate''s name appears separately on the ballot under each party''s line (e.g., Democratic and Working Families), and all votes cast for the candidate across those lines are aggregated into a single total.', 'https://www.nysenate.gov/legislation/laws/ELN/1-104', 'N.Y. Elec. Law § 1-104', '2026-05-11', 'static', 'statute_citation', 'All candidates and party committees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('eac055cacbccdb30', 'NY', '["state"]', 'ballot_access', 'What are the requirements for a political party to maintain automatic ballot access in New York?', '["How does a third party stay on the ballot in NY?","Party qualification threshold New York 130,000 votes","What is the threshold to be a recognized political party in NY?"]', 'To maintain recognized status, a party''s candidate for Governor or President (at the last preceding gubernatorial or presidential election) must receive at least 130,000 votes OR 2% of the total votes cast for that office, whichever is greater. As of 2026, the qualified parties are Democratic, Republican, Conservative, and Working Families.', 'https://www.nysenate.gov/legislation/laws/ELN/1-104', 'N.Y. Elec. Law § 1-104(3)', '2026-05-11', 'static', 'statute_citation', 'Third-party organizers and state committees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('af99da53d321afdc', 'NY', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the difference in authority between the New York State Board of Elections and the New York City Board of Elections?', '["Does the State BoE run elections in Brooklyn?","NYC Board of Elections vs State BoE","Who manages voting machines in Manhattan?"]', 'The State Board of Elections handles statewide campaign finance and general election law enforcement. However, the New York City Board of Elections (NYC BoE) is a separately constituted body that directly administers all voting, ballot printing, and polling locations strictly within the five boroughs of NYC. Campaigns operating in NYC must interact directly with the NYC BoE for ballot access and voter data.', 'https://vote.nyc/page/about-board', 'New York City Board of Elections', '2026-05-11', 'static', 'official_source_direct', 'Candidates and consultants operating within NYC', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('94b7e9b58cdaa13f', 'NY', '["municipal"]', 'runoff_rules', 'Does New York use Ranked-Choice Voting (RCV)?', '["Is ranked choice voting used for Governor in NY?","RCV rules New York City","Do I rank candidates for Congress in NY?"]', 'Ranked-Choice Voting (RCV) is used EXCLUSIVELY in New York City, and ONLY for Primary and Special Elections for five specific city offices: Mayor, Public Advocate, Comptroller, Borough President, and City Council. RCV is NOT used for General Elections, nor is it used anywhere outside of NYC or for state/federal offices.', 'https://vote.nyc/page/ranked-choice-voting', 'New York City Board of Elections – RCV Guide', '2026-05-11', 'static', 'official_source_direct', 'NYC Municipal Candidates and Voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('74528194c4587327', 'NY', '["judicial"]', 'ballot_access', 'How do candidates get on the ballot for the New York Supreme Court?', '["Are there primary elections for NY Supreme Court judges?","Judicial nominating conventions NY","How to run for Supreme Court in New York"]', 'Candidates for the New York Supreme Court (the state''s trial-level court of general jurisdiction) are not chosen through direct primary elections. Instead, they are nominated at Judicial Delegate Conventions by delegates who were elected by party voters during the primary.', 'https://www.nysenate.gov/legislation/laws/ELN/6-106', 'N.Y. Elec. Law § 6-106', '2026-05-11', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('229e17c30346066f', 'NY', '["state"]', 'finance_ethics', 'What is the New York Public Campaign Finance Program (PCFP)?', '["State matching funds NY","How does the PCFB matching system work?","Do state assembly candidates get public money?"]', 'The PCFP is a voluntary program where candidates for statewide office and the state legislature can receive public matching funds for small-dollar contributions ($5 to $250). To qualify, candidates must reach specific fundraising thresholds and collect a minimum number of donations from residents of their specific district or the state.', 'https://pcfb.ny.gov/program-overview', 'New York State Public Campaign Finance Board', '2026-05-11', 'static', 'official_source_direct', 'State-level candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('558c20af6ab9fdbb', 'NY', '["state"]', 'finance_ethics', 'What is the matching fund ratio for State Senate and State Assembly candidates in the PCFP?', '["Tiered matching funds NY legislature","How much does the state match for a $250 donation?","PCFB matching ratios breakpoints"]', 'For legislative candidates, the program uses a progressively tiered match for the first $250 of eligible in-district contributions. The first $50 is matched at 12-to-1. The next $100 ($51-$150) is matched at 9-to-1. The final $100 ($151-$250) is matched at 8-to-1. Therefore, a full $250 contribution yields $2,300 in public matching funds.', 'https://pcfb.ny.gov/candidate-committee-services', 'New York State Public Campaign Finance Board', '2026-05-11', 'per_cycle', 'official_source_direct', 'State Legislative candidates participating in PCFP', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('a1d20d61f99b122e', 'NY', '["state"]', 'finance_ethics', 'What is the matching fund ratio for Statewide candidates (Governor, AG, Comptroller) in the PCFP?', '["Governor matching funds ratio NY","Statewide public campaign finance limits","6-to-1 match New York"]', 'For participating statewide candidates (Governor, Lieutenant Governor, Attorney General, Comptroller), eligible in-state contributions between $5 and $250 are matched at a flat 6-to-1 ratio. A $100 contribution yields $600 in public funds.', 'https://pcfb.ny.gov/candidate-committee-services', 'New York State Public Campaign Finance Board', '2026-05-11', 'per_cycle', 'official_source_direct', 'Statewide candidates participating in PCFP', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('413bf9da6290e6c2', 'NY', '["federal"]', 'redistricting', 'Which congressional maps are in effect for the 2026 election cycle in New York?', '["Are the Hochul 2024 congressional maps still active?","Did the IRC draw the 2026 maps?","NY-11 redistricting lawsuit status 2026"]', 'As of early 2026, the congressional maps signed into law in February 2024 are in effect. While a state trial court struck down NY-11 as racially dilutive in January 2026, the U.S. Supreme Court issued a stay in March 2026 pending state appellate review, leaving the 2024 boundaries temporarily active.', 'https://www.nyirc.gov/congressional-plan', 'New York Independent Redistricting Commission', '2026-05-11', 'volatile', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('4071664812f6e9e0', 'NY', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for a candidate running for Governor of New York?', '["How much can an individual give to a Governor candidate in NY?","What is the max donation for statewide office in 2026?","NY Governor contribution limits 2026"]', 'For the 2025-2026 cycle, individuals and PACs may contribute up to $9,000 per election to a candidate for Governor, Attorney General, or Comptroller. This limit applies regardless of whether the candidate is participating in the Public Campaign Finance Program.', 'https://elections.ny.gov/2025-state-level-contribution-limits', 'New York State Board of Elections – Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'Statewide candidates and donors', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('4a49fd7fccd970b1', 'NY', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for State Senate and State Assembly in New York?', '["Max donation for NY State Assembly 2026","NY State Senate contribution limits","How much can I give to my local state representative in NY?"]', 'For the 2025-2026 cycle, the contribution limit for individuals and PACs giving to non-participating candidates is $5,000 per election for State Senate, and $3,000 per election for State Assembly. These limits are calculated per election cycle by the State BoE based on active registered voters.', 'https://elections.ny.gov/2025-state-level-contribution-limits', 'New York State Board of Elections – Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'State Legislative candidates and donors', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('298dd83908accaa6', 'NY', '["state","county","municipal"]', 'finance_ethics', 'How are Limited Liability Companies (LLCs) treated for campaign contribution limits in New York?', '["LLC loophole New York 2019 reform","Can my LLC donate to a NY candidate?","Do LLCs have the same limits as individuals in NY?"]', 'Following a January 2019 reform closing the ''LLC loophole'', an LLC may contribute a maximum aggregate of $5,000 in a single calendar year, combined across ALL state and local candidates. Furthermore, the contribution must be attributed proportionally to the LLC''s direct and indirect members from the very first dollar.', 'https://www.nysenate.gov/legislation/laws/ELN/14-116', 'N.Y. Elec. Law § 14-116', '2026-05-11', 'static', 'statute_citation', 'LLC owners and Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('bfbd8fea9f6e5418', 'NY', '["state"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for state office in New York?', '["Are corporate contributions legal in NY?","Can my business donate to a state candidate?","Corporate aggregate limit NY"]', 'Yes, but strictly limited. A corporation may contribute up to a total aggregate of $5,000 in a single calendar year, combined across all New York state and local candidates and political committees.', 'https://www.nysenate.gov/legislation/laws/ELN/14-116', 'N.Y. Elec. Law § 14-116', '2026-05-11', 'static', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('3d7e3bf4bde67999', 'NY', '["state"]', 'ballot_access', 'How many petition signatures are required for a statewide candidate to access the primary ballot in New York?', '["Signature requirement for NY Governor","How many signatures to run statewide in NY?","Geographic distribution rule for statewide petitions NY"]', 'A statewide candidate must collect 15,000 valid signatures, or 5% of enrolled party voters (whichever is less). Critically, this total must include at least 100 signatures (or 5% of enrolled voters) from each of at least one-half of the state''s congressional districts.', 'https://www.nysenate.gov/legislation/laws/ELN/6-136', 'N.Y. Elec. Law § 6-136(1)', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('88df37b35cf1c447', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the deadline to change party enrollment to vote in a closed primary in New York?', '["When must I register as a Democrat to vote in the NY primary?","Party change deadline New York 2026","Closed primary cut-off date NY"]', 'New York is a strict closed primary state. To vote in a party''s June primary, an already-registered voter wishing to change their party enrollment must submit the change no later than February 14 of the election year. Applications received after February 14 do not take effect until after the primary.', 'https://www.nysenate.gov/legislation/laws/ELN/5-304', 'N.Y. Elec. Law § 5-304(3)', '2026-05-11', 'per_cycle', 'statute_citation', 'Voters wishing to participate in primaries', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('bcf4b90c8a732c59', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the deadline for a new voter to register for the 2026 New York Primary or General Election?', '["Voter registration deadline NY 2026","10-day registration rule New York","When is the last day to register for the election?"]', 'Under New York''s 10-day rule, a new voter registration application must be received by the Board of Elections no later than 10 days before the election. For the June 23, 2026 primary, the deadline is June 13, 2026.', 'https://www.nysenate.gov/legislation/laws/ELN/5-210', 'N.Y. Elec. Law § 5-210', '2026-05-11', 'per_cycle', 'statute_citation', 'Unregistered voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c404fced54af79bc', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How many days of Early Voting does New York require?', '["Early voting period New York","When does early voting start in NY?","9-day early voting window"]', 'New York mandates a 9-day early voting period. Early voting begins on the tenth day prior to an election and ends on the second day prior to the election.', 'https://www.nysenate.gov/legislation/laws/ELN/8-600', 'N.Y. Elec. Law § 8-600', '2026-05-11', 'static', 'statute_citation', 'All voters and Get-Out-The-Vote operations', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('be390be68c3bade4', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in New York?', '["New York voter ID laws","Do I need my driver''s license to vote in NY?","Poll ID requirements NY"]', 'No. New York does not require a photo ID to vote at the polls. Only first-time voters who registered by mail without providing their driver''s license or Social Security number may be asked to show identification (which can include non-photo options like a utility bill).', 'https://elections.ny.gov/request-ballot', 'New York State Board of Elections', '2026-05-11', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('34379cf307a1be94', 'NY', '["state"]', 'recall_rules', 'Can voters circulate a recall petition to remove the Governor or other state officials in New York?', '["Statewide recall rules New York","How to recall a politician in NY","Does NY have a recall mechanism?"]', 'No. New York State does not have a general statutory or constitutional mechanism for voters to recall elected state officials. Removal of statewide officers is handled via the legislative impeachment process.', 'https://www.nysenate.gov/legislation/laws/CNS/A6', 'New York Constitution Article VI § 24', '2026-05-11', 'static', 'statute_citation', 'Voters and Statewide officials', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('b3c6a79c78e74012', 'NY', '["state"]', 'candidate_eligibility', 'What is the minimum age to run for Governor or Lieutenant Governor in New York?', '["How old do you have to be to be NY Governor?","Age requirement for Lt. Governor NY","Gubernatorial candidate age limit"]', 'A candidate for Governor or Lieutenant Governor must be at least 30 years old, a citizen of the United States, and a resident of New York for at least five years immediately preceding the election.', 'https://www.nysenate.gov/legislation/laws/CNS/A4', 'New York Constitution Article IV § 2', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('4058854258f7b314', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline and early voting period for the 2026 New York General Election?', '["When is the last day to register for the 2026 general election in NY?","General election early voting dates NY 2026","October registration deadline New York"]', 'Under the 10-day rule, voter registration applications for the General Election must be received by October 24, 2026. The mandated 9-day Early Voting period also begins on October 24, 2026, and runs through November 1, 2026.', 'https://elections.ny.gov/2026-election-deadlines-poster', 'New York State Board of Elections – Election Deadlines', '2026-05-11', 'per_cycle', 'official_source_direct', 'All voters and Get-Out-The-Vote operations', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c10ae6380014566b', 'NY', '["federal"]', 'ballot_access', 'How many petition signatures are required for a U.S. House candidate to access the primary ballot in New York?', '["Signature threshold for Congress NY","How many signatures to run for US House in New York?","Designating petition requirements Congressional District"]', 'To access the primary ballot via a designating petition, a candidate for the U.S. House of Representatives must collect 1,250 valid signatures from enrolled voters of their party within the congressional district, or 5% of the enrolled voters, whichever is less, under N.Y. Elec. Law § 6-136(2)(g).', 'https://www.nysenate.gov/legislation/laws/ELN/6-136', 'N.Y. Elec. Law § 6-136(2)(g)', '2026-05-11', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('fc8b090d4c09d43b', 'NY', '["state"]', 'ballot_access', 'What are the signature thresholds for State Senate and State Assembly designating petitions?', '["Signatures needed for NY State Legislature","How many signatures to run for State Assembly NY?","State Senate petition requirements 1000 signatures"]', 'A candidate for New York State Senate must collect 1,000 valid signatures from enrolled party voters within the district. A candidate for New York State Assembly must collect 500 valid signatures from enrolled party voters within the district (or 5% of enrolled voters, whichever is less).', 'https://www.nysenate.gov/legislation/laws/ELN/6-136', 'N.Y. Elec. Law § 6-136(2)(h-i)', '2026-05-11', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('bfc4a44f9f8d1b3c', 'NY', '["county","municipal"]', 'ballot_access', 'What is the petition signature threshold for county-level offices in New York?', '["How many signatures to run for county executive?","Local office petition rules NY","County legislature signature requirement"]', 'For county-level offices, the requirement is generally 5% of the enrolled voters of the party in the political subdivision. However, state law caps the maximum number of required signatures based on the population/size of the subdivision (e.g., capping at 2,000, 1,500, or 1,000 depending on the county).', 'https://www.nysenate.gov/legislation/laws/ELN/6-136', 'N.Y. Elec. Law § 6-136(2)', '2026-05-11', 'static', 'statute_citation', 'County and local candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('42e50ee03639d36c', 'NY', '["federal","state","county","municipal"]', 'ballot_access', 'What is an Independent Nominating Petition for U.S. House in New York?', '["Running as an independent in NY","Independent line ballot access New York","How do unaffiliated candidates get on the ballot?"]', 'Candidates without a recognized party line must file an Independent Nominating Petition to appear on the general election ballot. For U.S. House, this requires 3,500 valid signatures under N.Y. Elec. Law § 6-142(2)(e). These petitions are typically collected and filed during a specific window in April and May.', 'https://www.nysenate.gov/legislation/laws/ELN/6-142', 'N.Y. Elec. Law § 6-142', '2026-05-11', 'static', 'statute_citation', 'Independent and third-party candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('b42247ae3d22b0af', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does New York allow no-excuse absentee voting?', '["Can anyone vote by mail in NY?","Early Mail Voter Act New York","Do I need an excuse to get an absentee ballot in 2026?"]', 'Yes. The Early Mail Voter Act of 2023 allows any registered voter to request an ''Early Mail Ballot'' without a traditional excuse. This law survived a 2024 constitutional challenge (Stefanik v. Hochul) and is fully operational for the 2026 cycle.', 'https://www.nysenate.gov/legislation/laws/ELN/8-700', 'N.Y. Elec. Law § 8-700', '2026-05-11', 'static', 'statute_citation', 'All voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('92ada5fc9cd1654a', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What are the postmark and receipt deadlines for mail-in ballots in New York?', '["When is my absentee ballot due in NY?","7-day receipt deadline for ballots New York","Postmark rules for Early Mail Ballots"]', 'A mail ballot must be postmarked no later than Election Day. It will be counted as long as it is received by the County Board of Elections no later than 7 days after the election (e.g., November 10, 2026, for the General Election).', 'https://elections.ny.gov/2026-election-deadlines-poster', 'New York State Board of Elections – Election Deadlines', '2026-05-11', 'static', 'official_source_direct', 'All voters and Campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('41f20a412a38e1e9', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What is the difference between COELIG and the State Board of Elections for campaign compliance?', '["Who enforces campaign finance in NY?","JCOPE vs BOE vs COELIG","Where do I file my financial disclosure?"]', 'The State Board of Elections (BOE) Division of Election Law Enforcement handles all direct campaign finance reporting, contribution limits, and election law violations. The Commission on Ethics and Lobbying in Government (COELIG—formerly JCOPE) oversees financial disclosures for state officials, lobbying regulations, and broader ethics investigations.', 'https://ethics.ny.gov/about-coelig', 'New York State Commission on Ethics and Lobbying in Government', '2026-05-11', 'static', 'official_source_direct', 'Candidates, Consultants, and Lobbyists', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('fb1ea920879b2018', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What is the periodic and pre-election reporting schedule for campaign committees in New York?', '["When are campaign finance reports due in NY?","32-day pre-primary report deadline","New York periodic campaign filing dates"]', 'Committees must file two standard ''Periodic'' reports per year (January 15 and July 15). During an election where the candidate is on the ballot, committees must additionally file a 32-day pre-election report, an 11-day pre-election report, and a 27-day post-election report.', 'https://elections.ny.gov/system/files/documents/2025/12/2026-filing-calendar-12112025-approved.secure.accessible.pdf', 'New York State Board of Elections – Filing Calendar', '2026-05-11', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c6b9fbbfcf648666', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What is the 24-hour reporting rule for late contributions in New York?', '["When do I have to report late donations within 24 hours?","Late contribution timeframe NY","Reporting $1,000 donations right before the election"]', 'Under N.Y. Elec. Law § 14-108(1)(d), any contribution or loan exceeding $1,000 received during the 14 days immediately preceding an election must be reported to the Board of Elections within 24 hours of receipt. This applies exclusively to contributions and loans, not to expenditures.', 'https://www.nysenate.gov/legislation/laws/ELN/14-108', 'N.Y. Elec. Law § 14-108(1)(d)', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('4635bc3dc2e9b0d4', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How is the order of candidate names determined on the New York ballot?', '["Who gets listed first on the ballot in NY?","Is ballot order randomized in New York?","Randomized alphabet drawing BoE"]', 'Ballot order is determined by a ''Randomized Alphabet Drawing'' conducted by the Board of Elections. The order in which the alphabet is drawn dictates the order in which candidates appear under the respective party lines, neutralizing alphabetical advantage.', 'https://www.nysenate.gov/legislation/laws/ELN/7-116', 'N.Y. Elec. Law § 7-116', '2026-05-11', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c42cfdb937353758', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Does New York have a ''Sore Loser'' law that prevents primary losers from appearing on the general election ballot?', '["Can a candidate who loses the primary run on another line in NY?","Sore loser law under fusion voting","Running on the Working Families line after losing the Democratic primary"]', 'New York''s ''sore loser'' restriction is soft due to fusion voting. A candidate who loses a party primary is prohibited from filing an Independent Nominating Petition for that same office. However, if they already secured a different recognized party''s line (e.g., losing the Democratic primary but winning the Working Families primary), they will still appear on the general election ballot on that alternate line.', 'https://www.nysenate.gov/legislation/laws/ELN/6-146', 'N.Y. Elec. Law § 6-146', '2026-05-11', 'static', 'statute_citation', 'Candidates seeking multiple party lines', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('e3d41918b0b8f91d', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the Wilson-Pakula process in New York Election Law?', '["Can a Democrat run on the Republican line in NY?","Wilson-Pakula certificate of authorization","How do cross-endorsements work for non-enrolled members?"]', 'The Wilson-Pakula Act requires that if a candidate is not officially enrolled in a political party, they cannot be designated or nominated by that party unless the party''s appropriate committee explicitly issues a ''Certificate of Authorization'' permitting them to run on their line.', 'https://www.nysenate.gov/legislation/laws/ELN/6-120', 'N.Y. Elec. Law § 6-120(3)', '2026-05-11', 'static', 'statute_citation', 'Candidates seeking cross-endorsements', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('1f6a822826a456be', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How do the Conservative Party and Working Families Party typically utilize the Wilson-Pakula process?', '["WFP endorsement mechanics NY","Conservative Party cross endorsement","Third party lines New York"]', 'Because third parties have smaller voter bases, the Conservative Party frequently uses Wilson-Pakula authorizations to cross-endorse Republican candidates, while the Working Families Party uses it to cross-endorse Democratic candidates, allowing those candidates to aggregate votes from both lines under Fusion Voting.', 'https://www.nysenate.gov/legislation/laws/ELN/6-120', 'N.Y. Elec. Law § 6-120(3)', '2026-05-11', 'static', 'statute_citation', 'Campaign Strategists', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('a5127b2ae35a6f18', 'NY', '["federal","state","county","municipal"]', 'ballot_access', 'What is the ''placeholder candidate'' mechanism used by third parties like the Working Families Party?', '["WFP placeholder strategy NY","How does a party swap candidates off their line?","Nomination vacancy creation New York"]', 'A party may designate a ''placeholder'' candidate during the petition phase before major party primaries are decided. Because NY law only allows removing a candidate via death, declination, or disqualification, the party later cross-nominates the placeholder for a judicial office (disqualifying them from the original race), creating a legal vacancy that the party committee then fills with their true intended candidate.', 'https://www.nysenate.gov/legislation/laws/ELN/6-148', 'N.Y. Elec. Law § 6-148', '2026-05-11', 'static', 'statute_citation', 'Party Committees and Campaign Strategists', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('60db233347ac745f', 'NY', '["state"]', 'candidate_eligibility', 'What are the specific residency requirements to run for the New York State Legislature?', '["How long do I have to live in NY to run for State Senate?","Residency rules State Assembly NY","Do I have to live in the district to run?"]', 'Under New York Constitution Article III § 7, a candidate must be a resident of New York for 5 years, and a resident of the district for 12 months immediately preceding the election. Exception: in a redistricting year, they need only be a resident of the county containing the altered district for 12 months.', 'https://www.nysenate.gov/legislation/laws/CNS/A3', 'New York Constitution Article III § 7', '2026-05-11', 'static', 'statute_citation', 'State Legislative Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('a15477dde09c66bf', 'NY', '["federal"]', 'candidate_eligibility', 'What are the specific residency and age requirements to run for U.S. House in New York?', '["Do I have to live in the district to run for Congress in NY?","Age requirement for Congress New York","Can I run for a congressional seat if I live in a different district?"]', 'A U.S. House candidate must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of New York State when elected. The U.S. Constitution does not require the candidate to live within the specific congressional district boundaries.', 'https://elections.ny.gov/requirements-hold-office', 'New York State Board of Elections / U.S. Constitution Art. I § 2', '2026-05-11', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('34fce9fbf3488534', 'NY', '["municipal"]', 'candidate_eligibility', 'What are the term limits for local officials in New York City?', '["NYC Mayor term limits","Can a City Council member serve 3 terms in NY?","Term limits for Public Advocate and Comptroller"]', 'Under the NYC Charter, the Mayor, Public Advocate, Comptroller, Borough Presidents, and City Council members are strictly limited to serving two consecutive four-year terms.', 'https://codelibrary.amlegal.com/codes/newyorkcity/latest/NYCcharter/0-0-0-120', 'New York City Charter § 1137', '2026-05-11', 'static', 'statute_citation', 'NYC Municipal Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('52d9c311aeb5815a', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in New York while on parole or probation?', '["Felon voting rights NY","Can I vote after getting out of prison in New York?","Voting post-incarceration rules NY"]', 'Yes. A 2021 law automatically restores the right to vote for individuals convicted of a felony immediately upon their release from incarceration. Being on parole or post-release supervision does not restrict voting, though the individual must re-register.', 'https://elections.ny.gov/voting-after-incarceration', 'New York State Board of Elections – Voting After Incarceration', '2026-05-11', 'static', 'official_source_direct', 'All eligible citizens', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('23bea0a4179a756a', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the baseline eligibility requirements to register to vote in New York?', '["How long do I need to live in NY to vote?","Can 17 year olds vote in the primary NY?","Voter qualifications New York"]', 'To vote in New York, an individual must be a U.S. citizen, at least 18 years old by the date of the general election, and a resident of the state and the county, city, or village for at least 30 days before the election.', 'https://elections.ny.gov/voting-after-incarceration', 'New York State Board of Elections – Voter Qualifications', '2026-05-11', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('7fdaad78ced2d157', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is an Affidavit Ballot and when is it used?', '["Provisional ballot New York equivalent","Voting if my name isn''t on the poll book NY","How to cast an affidavit ballot"]', 'An Affidavit Ballot is New York''s equivalent to a provisional ballot. If a voter believes they are eligible but their name is missing from the poll book or their signature is missing, they are legally entitled to vote via paper affidavit ballot and sign an oath envelope, which officials verify post-election.', 'https://vote.nyc/page/understanding-ballot', 'New York City Board of Elections / N.Y. Elec. Law § 8-302', '2026-05-11', 'static', 'official_source_direct', 'Voters and poll watchers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c7e00d935094ac48', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the timeline for challenging a candidate''s petition signatures in New York?', '["General objections to petitions timeline","How to knock someone off the ballot NY","Specifications of objections deadline"]', 'Opponents must file ''General Objections'' with the Board of Elections within 3 days after the petition is filed. Then, detailed ''Specifications of Objections'' (outlining exactly which signatures are invalid and why) must be filed within 6 days following the filing of the General Objection.', 'https://www.nysenate.gov/legislation/laws/ELN/6-154', 'N.Y. Elec. Law § 6-154', '2026-05-11', 'static', 'statute_citation', 'Campaigns and Election Lawyers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('d5fa45ea39771832', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Under what circumstances can a party substitute a candidate after nominations are finalized?', '["How to replace a candidate on the ballot NY","Vacated nominations substitution rules","Can a candidate withdraw after winning the primary in NY?"]', 'New York law restricts removing or substituting a candidate once nominated. A vacancy can generally only be created and filled if the candidate dies, officially declines the nomination within a very narrow statutory window, or becomes legally disqualified (e.g., by moving out of state or being nominated for a judgeship).', 'https://www.nysenate.gov/legislation/laws/ELN/6-148', 'N.Y. Elec. Law § 6-148', '2026-05-11', 'static', 'statute_citation', 'Party Committees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('6324669661e97039', 'NY', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the procedure for running as a write-in candidate in New York?', '["Do write-in candidates have to register in NY?","How to legally canvass write-in votes","Certificate of Candidacy write in NY"]', 'Voters can write in any name on the ballot. However, to ensure write-in votes are officially tallied and canvassed, a write-in candidate must file a Certificate of Candidacy with the Board of Elections no later than 27 days before the primary or general election.', 'https://www.nysenate.gov/legislation/laws/ELN/6-153', 'N.Y. Elec. Law § 6-153', '2026-05-11', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('827211ef7b494f94', 'NY', '["state","county","municipal"]', 'finance_ethics', 'Are candidates in New York allowed to use campaign funds for personal expenses?', '["Personal use of campaign funds NY","Can I buy a car with campaign money?","New York rules on spending campaign donations"]', 'No. New York Election Law explicitly prohibits the conversion of campaign funds to a personal use. Expenditures must be exclusively related to the candidate''s campaign or the execution of their public office duties.', 'https://www.nysenate.gov/legislation/laws/ELN/14-130', 'N.Y. Elec. Law § 14-130', '2026-05-11', 'static', 'statute_citation', 'All state and local candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('a54414582326a78a', 'NY', '["federal"]', 'ballot_access', 'What is the petition signature requirement to run for U.S. Senate in New York?', '["How many signatures to run for Senate in NY?","Senate ballot access NY","Statewide federal signature requirements"]', 'Although there is no regular U.S. Senate election in NY in 2026, the statewide designating petition requirement is 15,000 valid signatures (or 5% of enrolled voters), including at least 100 signatures from each of at least half of the state''s 26 congressional districts.', 'https://www.nysenate.gov/legislation/laws/ELN/6-136', 'N.Y. Elec. Law § 6-136(1)', '2026-05-11', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('943ae44815018c9a', 'NY', '["state"]', 'candidate_eligibility', 'What are the residency requirements to run for Governor, Attorney General, or Comptroller in New York?', '["How long do I need to live in NY to run for AG?","Residency rules for statewide office","Do I have to be a NY resident to run for Comptroller?"]', 'Under the New York Constitution, candidates for Governor, Lieutenant Governor, Attorney General, and State Comptroller must be citizens, at least 30 years old, and residents of New York State for at least five years immediately preceding the election.', 'https://www.nysenate.gov/legislation/laws/CNS/A5', 'New York Constitution Article V § 1', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('338fc5ac0f791268', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the state restrictions on placing campaign signs near highways in New York?', '["Can I put political signs on state roads?","NYSDOT campaign sign rules","Where are campaign signs prohibited in NY?"]', 'Under New York State Department of Transportation (NYSDOT) regulations, it is illegal to place political campaign signs within the state highway right-of-way. Signs placed illegally are subject to immediate removal and confiscation by NYSDOT crews.', 'https://www.dot.ny.gov/news/press-releases/2022/2022-10-18', 'New York State Department of Transportation', '2026-05-11', 'static', 'official_source_direct', 'All campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('0124f33628cb8fef', 'NY', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclosure requirements for campaign text messages (SMS) and robocalls in New York?', '["Do campaign texts need an ''Ad paid for by'' disclaimer?","Robocall disclosure requirements NY","SMS political rules New York"]', 'Political robocalls and SMS text messages must include explicit ''Paid for by'' disclosures and comply with federal TCPA consent standards. NY law strictly prohibits anonymous mass political communications, requiring the sponsor''s identity to be clearly stated.', 'https://www.nysenate.gov/legislation/laws/ELN/14-106', 'N.Y. Elec. Law § 14-106', '2026-05-11', 'static', 'statute_citation', 'All campaigns utilizing digital communication', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('5c6c41427317c2f2', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What are the digital advertising disclosure rules for New York campaigns?', '["Democracy Protection Act NY","Do Facebook ads need disclaimers in New York?","Digital political ad rules"]', 'Under the Democracy Protection Act, all paid internet and digital political advertisements must clearly display a ''Paid for by'' disclosure. Social media platforms are also required to maintain a public archive of political ads purchased by independent expenditure committees.', 'https://www.nysenate.gov/legislation/laws/ELN/14-107-B', 'N.Y. Elec. Law § 14-107-b', '2026-05-11', 'static', 'statute_citation', 'Digital strategists and campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('1c7c672e84fc577f', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What triggers the requirement to report an Independent Expenditure in New York?', '["When does an independent group have to file?","Independent expenditure definition NY","Reporting threshold for Super PACs New York"]', 'Under N.Y. Elec. Law § 14-107, an independent expenditure is a communication that expressly advocates for or against a candidate, made without coordination. Any person or entity making independent expenditures aggregating $1,000 or more must file disclosures with the State BoE.', 'https://www.nysenate.gov/legislation/laws/ELN/14-107', 'N.Y. Elec. Law § 14-107', '2026-05-11', 'static', 'statute_citation', 'Super PACs and Independent Expenditure Committees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('656a178788f6c0f3', 'NY', '["state","county","municipal"]', 'finance_ethics', 'When must an Independent Expenditure Committee register in New York?', '["How to form an IEC in NY","Registration deadline for Super PACs","Independent expenditure registration"]', 'An Independent Expenditure Committee (IEC) must formally register with the State Board of Elections by filing a statement of organization before making any independent expenditures that aggregate to $1,000 or more.', 'https://www.nysenate.gov/legislation/laws/ELN/14-107', 'N.Y. Elec. Law § 14-107(3)', '2026-05-11', 'static', 'statute_citation', 'Independent Expenditure Committees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('eaa4bef9acb4d7c8', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for filing campaign finance reports late with the New York State Board of Elections?', '["How much is the fine for late campaign reports in NY?","State BoE late filing penalties","What happens if I miss the reporting deadline?"]', 'The State BoE Division of Election Law Enforcement can impose civil penalties for late filing. Penalties typically range up to $1,000 for a first-time failure to file a standard periodic report, and up to $1,000 or the cost of the communication for late independent expenditure reports.', 'https://www.nysenate.gov/legislation/laws/ELN/14-126', 'N.Y. Elec. Law § 14-126', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('c1152f23e575974c', 'NY', '["state"]', 'finance_ethics', 'What is the process for filing an ethics complaint against a state official with COELIG?', '["How to report ethics violations NY","Filing a complaint with JCOPE/COELIG","Who investigates conflicts of interest for state legislators?"]', 'The Commission on Ethics and Lobbying in Government (COELIG) investigates complaints regarding violations of the state''s ethics laws, such as conflicts of interest or improper gifts. Complaints can be filed securely online or by mail, and COELIG has subpoena power to investigate.', 'https://ethics.ny.gov/report-misconduct', 'New York State Commission on Ethics and Lobbying in Government', '2026-05-11', 'static', 'official_source_direct', 'Voters and Consultants', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('1c2ac5339b28ced0', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What is the Form CF-02 and when must a candidate file it in New York?', '["How to register a campaign committee NY","Statement of Organization deadline","CF-02 filing requirements"]', 'Form CF-02 is the Committee Registration/Statement of Organization form. It must be filed with the State Board of Elections within 5 days after a candidate or committee chooses a treasurer and a depository bank, which must be done before receiving or spending any funds.', 'https://elections.ny.gov/campaign-finance-forms', 'New York State Board of Elections', '2026-05-11', 'static', 'official_source_direct', 'Candidates and Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('f1ff01ffbb969a9a', 'NY', '["state","county","municipal"]', 'finance_ethics', 'How long must a campaign treasurer retain campaign finance records in New York?', '["Campaign record retention requirements NY","How many years to keep campaign receipts?","BoE audit record retention"]', 'Under New York Election Law, a campaign treasurer must preserve all detailed accounts, records, bills, and receipts verifying their campaign finance disclosure statements for five years from the date of filing the statement to which they pertain.', 'https://www.nysenate.gov/legislation/laws/ELN/14-118', 'N.Y. Elec. Law § 14-118', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('5b4c2afba9656b59', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds in New York?', '["Surplus funds disposition NY","Can I give my leftover campaign money to charity?","What happens to campaign money when I close my committee?"]', 'Surplus campaign funds cannot be used for personal benefit. They may be returned to donors pro-rata, transferred to a party committee, donated to a 501(c)(3) charity, or held in the committee account for a future election campaign by the same candidate.', 'https://www.nysenate.gov/legislation/laws/ELN/14-130', 'N.Y. Elec. Law § 14-130', '2026-05-11', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('d599b94d63deda34', 'NY', '["state","county","municipal"]', 'finance_ethics', 'Are foreign nationals prohibited from contributing to state and local campaigns in New York?', '["Can a foreign citizen donate to my city council race?","Foreign contribution ban NY","Are non-citizens allowed to give to New York campaigns?"]', 'Yes. Following recent legislative amendments to N.Y. Elec. Law § 14-116-a, it is a felony for hostile foreign nations, their entities, or any foreign national to make contributions or independent expenditures in connection with any New York state or local election.', 'https://www.nysenate.gov/legislation/laws/ELN/14-116-A', 'N.Y. Elec. Law § 14-116-a', '2026-05-11', 'static', 'statute_citation', 'All state and local campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('2f74925a573b6a7c', 'NY', '["federal","state","county","municipal"]', 'ballot_access', 'How do the Conservative Party and Working Families Party formally endorse candidates who are not enrolled members?', '["Third party endorsement process NY","Conservative party convention rules","How to get the WFP endorsement"]', 'Third parties hold executive committee meetings or conventions to formally authorize cross-endorsements. Under the Wilson-Pakula Act, the party''s state or county executive committee must issue a Certificate of Authorization for the non-enrolled candidate to legally appear on their ballot line.', 'https://www.nysenate.gov/legislation/laws/ELN/6-120', 'N.Y. Elec. Law § 6-120', '2026-05-11', 'static', 'statute_citation', 'Candidates seeking third-party lines', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('07fe3a885dba8a89', 'NY', '["state"]', 'finance_ethics', 'What is the Financial Disclosure Statement (FDS) for New York state officials?', '["Do legislators have to disclose outside income?","COELIG FDS rules","What financial information is public for NY politicians?"]', 'Statewide elected officials, state legislators, and certain high-level state employees must file an annual Financial Disclosure Statement (FDS) with COELIG by May 15. The FDS requires the disclosure of outside income, investments, real estate, and potential conflicts of interest.', 'https://ethics.ny.gov/financial-disclosure', 'New York State Commission on Ethics and Lobbying in Government', '2026-05-11', 'static', 'official_source_direct', 'State officials and Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('f95cbfff1f976e09', 'NY', '["state","county","municipal"]', 'finance_ethics', 'What are examples of impermissible personal uses of campaign funds in New York?', '["Can campaign funds pay for my country club membership?","What is considered personal use of donations NY?","Illegal ways to spend campaign money"]', 'Impermissible personal uses include paying for a candidate''s personal mortgage or rent, clothing (other than campaign promotional apparel), country club memberships, personal vacations, and tuition payments that are not directly related to the campaign or public office.', 'https://www.nysenate.gov/legislation/laws/ELN/14-130', 'N.Y. Elec. Law § 14-130', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers and Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('4e294792d06a5201', 'NY', '["state"]', 'finance_ethics', 'What role does the New York State Comptroller play in the Public Campaign Finance Program (PCFP)?', '["Who audits the state matching funds NY?","Comptroller oversight of PCFB","Does the state audit participating campaigns?"]', 'While the PCFP is administered by the Public Campaign Finance Board, the State Comptroller is responsible for managing the state''s campaign finance fund and conducting post-election audits of participating campaigns to ensure public matching funds were spent legally.', 'https://pcfb.ny.gov/program-overview', 'New York State Public Campaign Finance Board', '2026-05-11', 'static', 'official_source_direct', 'Participating PCFP Campaigns', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('ba784b3ce4256aaa', 'NY', '["municipal"]', 'finance_ethics', 'Are contribution limits for New York City offices different from the New York State limits?', '["NYC Mayor contribution limits vs NY Governor","Do city candidates follow State BoE limits?","NYC CFB rules on max donations"]', 'Yes. The New York City Campaign Finance Board (NYC CFB) enforces separate, much stricter contribution limits for city offices (Mayor, Public Advocate, Comptroller, Borough President, City Council) than the State BoE limits for state offices. A NYC Mayoral candidate limit is $2,100, far below the Governor''s $9,000.', 'https://www.nyccfb.info/candidate-services/limits-and-thresholds/', 'New York City Campaign Finance Board', '2026-05-11', 'per_cycle', 'official_source_direct', 'NYC Municipal Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('0fd06626077e0e9b', 'NY', '["municipal"]', 'finance_ethics', 'How does the New York City matching funds program differ from the state PCFP?', '["NYC 8 to 1 matching funds vs state program","How much does the NYC CFB match?","City council matching fund ratio"]', 'The NYC Campaign Finance Board operates its own matching program for city offices. It provides an 8-to-1 match for the first $250 of an eligible NYC resident''s contribution (up to $2,000 in public funds per donor), whereas the state PCFP has a tiered 12:1/9:1/8:1 ratio for legislative races and 6:1 for statewide races.', 'https://www.nyccfb.info/get-involved/matching-funds-program/', 'New York City Campaign Finance Board', '2026-05-11', 'static', 'official_source_direct', 'NYC Municipal Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('abff37ccd97bff91', 'NY', '["municipal"]', 'finance_ethics', 'What are the ''Doing Business'' limits for New York City candidates?', '["Can developers donate to the Mayor?","NYC CFB lobbyist contribution limits","Doing business definition CFB"]', 'The NYC CFB enforces strict ''Doing Business'' limits on contributions from individuals who have financial dealings with the city (e.g., lobbyists, contractors, developers). For a Mayoral candidate, a person ''doing business'' with the city can only contribute $400, and these contributions are not eligible for public matching funds.', 'https://www.nyccfb.info/candidate-services/limits-and-thresholds/', 'New York City Campaign Finance Board', '2026-05-11', 'static', 'official_source_direct', 'NYC Municipal Candidates and City Contractors', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('706535fe8073d473', 'NY', '["judicial"]', 'election_dates', 'How are judges selected for the New York Court of Appeals?', '["Are Court of Appeals judges elected in NY?","Highest court selection process New York","How long do NY highest court judges serve?"]', 'Judges for the New York Court of Appeals (the state''s highest court) are not elected. They are appointed by the Governor from a shortlist provided by the Commission on Judicial Nomination and must be confirmed by the State Senate to serve 14-year terms.', 'https://www.nysenate.gov/legislation/laws/CNS/A6', 'New York Constitution Article VI § 2', '2026-05-11', 'static', 'statute_citation', 'Judicial nominees', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('ab20a9869ff971d0', 'NY', '["judicial"]', 'election_dates', 'How are Town and Village Justice Court judges elected in New York?', '["Are local justices elected in NY?","Village court judge elections","Do town judges run with a party label?"]', 'Town and Village Justices are elected locally in partisan or nonpartisan elections, depending on the specific municipality''s rules. They serve 4-year terms and have jurisdiction over local matters, misdemeanors, and minor civil claims.', 'https://www.nysenate.gov/legislation/laws/CNS/A6', 'New York Constitution Article VI § 17', '2026-05-11', 'static', 'statute_citation', 'Local Judicial Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('fe136314800e9ce0', 'NY', '["state"]', 'election_dates', 'How are vacancies in the New York State Legislature filled?', '["Special election for State Assembly NY","How is a vacant state senate seat filled?","Do special elections have primaries in NY?"]', 'Vacancies in the State Legislature are filled by special elections called by the Governor. Critically, there are no primary elections for these special elections; the respective county party committees directly nominate their candidates to appear on the special election ballot.', 'https://www.nysenate.gov/legislation/laws/ELN/6-114', 'N.Y. Elec. Law § 6-114', '2026-05-11', 'static', 'statute_citation', 'Party Committees and State Legislative Candidates', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('d86074a23eae3297', 'NY', '["municipal"]', 'candidate_eligibility', 'How do term limits work for New York City Council members during a redistricting cycle?', '["Can a NYC Council member serve 3 terms?","2-4-4 term limits NYC","Redistricting effect on city council terms"]', 'Normally, NYC Council members are limited to two consecutive 4-year terms. However, due to redistricting every 20 years, the terms follow a 2-year, 4-year, 4-year pattern (e.g., 2021, 2023, 2027) so members can technically serve up to three consecutive terms if one is a 2-year term.', 'https://codelibrary.amlegal.com/codes/newyorkcity/latest/NYCcharter/0-0-0-59', 'New York City Charter § 25', '2026-05-11', 'static', 'statute_citation', 'NYC City Council Members', 'batch_2026-05-11T20-08-03_new_york_full_v1'),
  ('dd53144bf245acd9', 'NY', '["judicial"]', 'ballot_access', 'Why does New York use Judicial Delegate Conventions for Supreme Court nominations instead of direct primaries?', '["Lopez Torres Supreme Court case New York","Is the judicial convention system constitutional?","Why don''t we vote for Supreme Court nominees directly?"]', 'New York uses Judicial Delegate Conventions to nominate Supreme Court justices to promote geographic and demographic diversity and insulate trial judges from direct retail campaigning. This convention system was upheld as constitutional by the U.S. Supreme Court in Lopez Torres v. NY State Bd. of Elections (2008).', 'https://www.supremecourt.gov/opinions/07pdf/06-766.pdf', 'NYS Bd. of Elections v. Lopez Torres, 552 U.S. 196 (2008)', '2026-05-11', 'static', 'secondary_source', 'Judicial candidates and party delegates', 'batch_2026-05-11T20-08-03_new_york_full_v1')
